import React, { useState } from "react";
import "./RegisterPage.css";
import logo from "../../icons/logo.png";
import { useNavigate } from "react-router-dom";

interface RegisterErrors {
  fullName?: string;
  email?: string;
  password?: string;
  confirmPassword?: string;
}

const getPasswordStrength = (p: string): "weak" | "medium" | "strong" | null => {
  if (!p) return null;
  const hasUpper = /[A-Z]/.test(p);
  const hasNumber = /[0-9]/.test(p);
  const hasSpecial = /[^A-Za-z0-9]/.test(p);
  if (p.length >= 8 && hasUpper && hasNumber && hasSpecial) return "strong";
  if (p.length >= 6 && (hasUpper || hasNumber)) return "medium";
  return "weak";
};

const strengthLabel = { weak: "Слабкий", medium: "Середній", strong: "Надійний" };

export const RegisterPage: React.FC = () => {
  const navigate = useNavigate();

  const [fullName, setFullName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [errors, setErrors] = useState<RegisterErrors>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const validate = (
    name: string,
    mail: string,
    pass: string,
    confirm: string
  ): RegisterErrors => {
    const errs: RegisterErrors = {};

    if (!name.trim()) {
      errs.fullName = "Введіть ПІП";
    } else if (name.trim().length < 3) {
      errs.fullName = "Мінімум 3 символи";
    }

    if (!mail.trim()) {
      errs.email = "Введіть email";
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(mail)) {
      errs.email = "Невірний формат email";
    }

    if (!pass) {
      errs.password = "Введіть пароль";
    } else if (pass.length < 6) {
      errs.password = "Мінімум 6 символів";
    }

    if (!confirm) {
      errs.confirmPassword = "Підтвердіть пароль";
    } else if (confirm !== pass) {
      errs.confirmPassword = "Паролі не співпадають";
    }

    return errs;
  };

  const handleBlur = (field: string) => {
    setTouched((prev) => ({ ...prev, [field]: true }));
    setErrors(validate(fullName, email, password, confirmPassword));
  };

  const handleChange = (field: string, value: string) => {
    if (field === "fullName") setFullName(value);
    if (field === "email") setEmail(value);
    if (field === "password") setPassword(value);
    if (field === "confirmPassword") setConfirmPassword(value);

    if (touched[field]) {
      const updated = {
        fullName,
        email,
        password,
        confirmPassword,
        [field]: value,
      };
      setErrors(validate(updated.fullName, updated.email, updated.password, updated.confirmPassword));
    }
  };

  const handleRegister = () => {
    const errs = validate(fullName, email, password, confirmPassword);
    setTouched({ fullName: true, email: true, password: true, confirmPassword: true });
    setErrors(errs);
    if (Object.keys(errs).length === 0) {
      // TODO: API call
      navigate("/distribution");
    }
  };

  const strength = getPasswordStrength(password);

  return (
    <div className="register-wrapper">
      <div className="register-header">
        <img className="register-logo" src={logo} alt="logo" />
        <div>
          <div className="register-brand-name">HORAND Partnership</div>
          <p className="register-subtitle">Створіть акаунт</p>
        </div>
      </div>

      <div className="register-card">
        {/* Full name */}
        <div className="input-group">
          <label className="input-label">ПІП</label>
          <input
            className={`input-field${touched.fullName && errors.fullName ? " input-error" : ""}`}
            type="text"
            placeholder="Іваненко Іван Іванович"
            value={fullName}
            onChange={(e) => handleChange("fullName", e.target.value)}
            onBlur={() => handleBlur("fullName")}
          />
          {touched.fullName && errors.fullName && (
            <span className="error-msg">{errors.fullName}</span>
          )}
        </div>

        {/* Email */}
        <div className="input-group">
          <label className="input-label">Email</label>
          <input
            className={`input-field${touched.email && errors.email ? " input-error" : ""}`}
            type="email"
            placeholder="example@email.com"
            value={email}
            onChange={(e) => handleChange("email", e.target.value)}
            onBlur={() => handleBlur("email")}
          />
          {touched.email && errors.email && (
            <span className="error-msg">{errors.email}</span>
          )}
        </div>

        {/* Password */}
        <div className="input-group">
          <label className="input-label">Пароль</label>
          <div className="password-wrap">
            <input
              className={`input-field${touched.password && errors.password ? " input-error" : ""}`}
              type={showPassword ? "text" : "password"}
              placeholder="Мінімум 6 символів"
              value={password}
              onChange={(e) => handleChange("password", e.target.value)}
              onBlur={() => handleBlur("password")}
            />
            <button
              className="password-toggle"
              onClick={() => setShowPassword((p) => !p)}
              tabIndex={-1}
            >
              {showPassword ? "🙈" : "👁"}
            </button>
          </div>
          {/* Strength bars */}
          {password && (
            <>
              <div className="password-strength">
                <div className={`strength-bar ${strength === "weak" || strength === "medium" || strength === "strong" ? strength : ""}`} />
                <div className={`strength-bar ${strength === "medium" || strength === "strong" ? strength : ""}`} />
                <div className={`strength-bar ${strength === "strong" ? strength : ""}`} />
              </div>
              <span className={`strength-label ${strength ?? ""}`}>
                {strength ? strengthLabel[strength] : ""}
              </span>
            </>
          )}
          {touched.password && errors.password && (
            <span className="error-msg">{errors.password}</span>
          )}
        </div>

        {/* Confirm password */}
        <div className="input-group">
          <label className="input-label">Підтвердіть пароль</label>
          <div className="password-wrap">
            <input
              className={`input-field${touched.confirmPassword && errors.confirmPassword ? " input-error" : ""}`}
              type={showConfirm ? "text" : "password"}
              placeholder="Повторіть пароль"
              value={confirmPassword}
              onChange={(e) => handleChange("confirmPassword", e.target.value)}
              onBlur={() => handleBlur("confirmPassword")}
            />
            <button
              className="password-toggle"
              onClick={() => setShowConfirm((p) => !p)}
              tabIndex={-1}
            >
              {showConfirm ? "🙈" : "👁"}
            </button>
          </div>
          {touched.confirmPassword && errors.confirmPassword && (
            <span className="error-msg">{errors.confirmPassword}</span>
          )}
        </div>

        <button className="register-button" onClick={handleRegister}>
          Зареєструватись
        </button>
      </div>

      <p className="login-text">
        Вже маєте акаунт?{" "}
        <button className="login-link" onClick={() => navigate("/login")}>
          Увійти
        </button>
      </p>
    </div>
  );
};
